def equal_list[A : equal](x0 : List[A], x1 : List[A]) : Boolean = (x0, x1)
  match {
  case (Nil, x21 :: x22) => false
  case (x21 :: x22, Nil) => false
  case (x21 :: x22, y21 :: y22) => eq[A](x21, y21) && equal_list[A](x22, y22)
  case (Nil, Nil) => true
}

def equal_rexp[A : equal](x0 : rexp[A], x1 : rexp[A]) : Boolean = (x0, x1)
  match {
  case (Rec(x101, x102), Charset(x11)) => false
  case (Charset(x11), Rec(x101, x102)) => false
  case (From(x91, x92), Charset(x11)) => false
  case (Charset(x11), From(x91, x92)) => false
  case (From(x91, x92), Rec(x101, x102)) => false
  case (Rec(x101, x102), From(x91, x92)) => false
  case (Upto(x81, x82), Charset(x11)) => false
  case (Charset(x11), Upto(x81, x82)) => false
  case (Upto(x81, x82), Rec(x101, x102)) => false
  case (Rec(x101, x102), Upto(x81, x82)) => false
  case (Upto(x81, x82), From(x91, x92)) => false
  case (From(x91, x92), Upto(x81, x82)) => false
  case (NTimes(x71, x72), Charset(x11)) => false
  case (Charset(x11), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Rec(x101, x102)) => false
  case (Rec(x101, x102), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), From(x91, x92)) => false
  case (From(x91, x92), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Upto(x81, x82)) => false
  case (Upto(x81, x82), NTimes(x71, x72)) => false
  case (Star(x6), Charset(x11)) => false
  case (Charset(x11), Star(x6)) => false
  case (Star(x6), Rec(x101, x102)) => false
  case (Rec(x101, x102), Star(x6)) => false
  case (Star(x6), From(x91, x92)) => false
  case (From(x91, x92), Star(x6)) => false
  case (Star(x6), Upto(x81, x82)) => false
  case (Upto(x81, x82), Star(x6)) => false
  case (Star(x6), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Star(x6)) => false
  case (Times(x51, x52), Charset(x11)) => false
  case (Charset(x11), Times(x51, x52)) => false
  case (Times(x51, x52), Rec(x101, x102)) => false
  case (Rec(x101, x102), Times(x51, x52)) => false
  case (Times(x51, x52), From(x91, x92)) => false
  case (From(x91, x92), Times(x51, x52)) => false
  case (Times(x51, x52), Upto(x81, x82)) => false
  case (Upto(x81, x82), Times(x51, x52)) => false
  case (Times(x51, x52), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Times(x51, x52)) => false
  case (Times(x51, x52), Star(x6)) => false
  case (Star(x6), Times(x51, x52)) => false
  case (Plus(x41, x42), Charset(x11)) => false
  case (Charset(x11), Plus(x41, x42)) => false
  case (Plus(x41, x42), Rec(x101, x102)) => false
  case (Rec(x101, x102), Plus(x41, x42)) => false
  case (Plus(x41, x42), From(x91, x92)) => false
  case (From(x91, x92), Plus(x41, x42)) => false
  case (Plus(x41, x42), Upto(x81, x82)) => false
  case (Upto(x81, x82), Plus(x41, x42)) => false
  case (Plus(x41, x42), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Plus(x41, x42)) => false
  case (Plus(x41, x42), Star(x6)) => false
  case (Star(x6), Plus(x41, x42)) => false
  case (Plus(x41, x42), Times(x51, x52)) => false
  case (Times(x51, x52), Plus(x41, x42)) => false
  case (Atom(x3), Charset(x11)) => false
  case (Charset(x11), Atom(x3)) => false
  case (Atom(x3), Rec(x101, x102)) => false
  case (Rec(x101, x102), Atom(x3)) => false
  case (Atom(x3), From(x91, x92)) => false
  case (From(x91, x92), Atom(x3)) => false
  case (Atom(x3), Upto(x81, x82)) => false
  case (Upto(x81, x82), Atom(x3)) => false
  case (Atom(x3), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Atom(x3)) => false
  case (Atom(x3), Star(x6)) => false
  case (Star(x6), Atom(x3)) => false
  case (Atom(x3), Times(x51, x52)) => false
  case (Times(x51, x52), Atom(x3)) => false
  case (Atom(x3), Plus(x41, x42)) => false
  case (Plus(x41, x42), Atom(x3)) => false
  case (One(), Charset(x11)) => false
  case (Charset(x11), One()) => false
  case (One(), Rec(x101, x102)) => false
  case (Rec(x101, x102), One()) => false
  case (One(), From(x91, x92)) => false
  case (From(x91, x92), One()) => false
  case (One(), Upto(x81, x82)) => false
  case (Upto(x81, x82), One()) => false
  case (One(), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), One()) => false
  case (One(), Star(x6)) => false
  case (Star(x6), One()) => false
  case (One(), Times(x51, x52)) => false
  case (Times(x51, x52), One()) => false
  case (One(), Plus(x41, x42)) => false
  case (Plus(x41, x42), One()) => false
  case (One(), Atom(x3)) => false
  case (Atom(x3), One()) => false
  case (Zero(), Charset(x11)) => false
  case (Charset(x11), Zero()) => false
  case (Zero(), Rec(x101, x102)) => false
  case (Rec(x101, x102), Zero()) => false
  case (Zero(), From(x91, x92)) => false
  case (From(x91, x92), Zero()) => false
  case (Zero(), Upto(x81, x82)) => false
  case (Upto(x81, x82), Zero()) => false
  case (Zero(), NTimes(x71, x72)) => false
  case (NTimes(x71, x72), Zero()) => false
  case (Zero(), Star(x6)) => false
  case (Star(x6), Zero()) => false
  case (Zero(), Times(x51, x52)) => false
  case (Times(x51, x52), Zero()) => false
  case (Zero(), Plus(x41, x42)) => false
  case (Plus(x41, x42), Zero()) => false
  case (Zero(), Atom(x3)) => false
  case (Atom(x3), Zero()) => false
  case (Zero(), One()) => false
  case (One(), Zero()) => false
  case (Charset(x11), Charset(y11)) => eq[set[A]](x11, y11)
  case (Rec(x101, x102), Rec(y101, y102)) =>
    equal_list[char](x101, y101) && equal_rexp[A](x102, y102)
  case (From(x91, x92), From(y91, y92)) =>
    equal_rexp[A](x91, y91) && equal_nat(x92, y92)
  case (Upto(x81, x82), Upto(y81, y82)) =>
    equal_rexp[A](x81, y81) && equal_nat(x82, y82)
  case (NTimes(x71, x72), NTimes(y71, y72)) =>
    equal_rexp[A](x71, y71) && equal_nat(x72, y72)
  case (Star(x6), Star(y6)) => equal_rexp[A](x6, y6)
  case (Times(x51, x52), Times(y51, y52)) =>
    equal_rexp[A](x51, y51) && equal_rexp[A](x52, y52)
  case (Plus(x41, x42), Plus(y41, y42)) =>
    equal_rexp[A](x41, y41) && equal_rexp[A](x42, y42)
  case (Atom(x3), Atom(y3)) => eq[A](x3, y3)
  case (One(), One()) => true
  case (Zero(), Zero()) => true
}

def F_RIGHT[A, B](f : A => vala[B], v : A) : vala[B] = Right[B](f(v))

def F_Plus[A](f_1 : (vala[A]) => vala[A], f_2 : (vala[A]) => vala[A],
               x2 : vala[A]) : vala[A]
  =
  (f_1, f_2, x2) match {
  case (f_1, f_2, Right(v)) => Right[A](f_2(v))
  case (f_1, f_2, Left(v)) => Left[A](f_1(v))
  case (f1, f2, Void()) => Void[A]()
  case (f1, f2, Atm(va)) => Atm[A](va)
  case (f1, f2, Seq(va, vb)) => Seq[A](va, vb)
  case (f1, f2, Stars(va)) => Stars[A](va)
  case (f1, f2, Recv(va, vb)) => Recv[A](va, vb)
}

def F_LEFT[A, B](f : A => vala[B], v : A) : vala[B] = Left[B](f(v))

def simp_Plus[A : equal,
               B](x0 : (rexp[A], (vala[B]) => vala[B]),
                   x1 : (rexp[A],
                          (vala[B]) =>
                            vala[B])) : (rexp[A], (vala[B]) => vala[B])
  =
  (x0, x1) match {
  case ((Zero(), f_1), (r_2, f_2)) =>
    (r_2, ((a : vala[B]) => F_RIGHT[vala[B], B](f_2, a)))
  case ((One(), f_1), (Zero(), f_2)) =>
    (One[A](), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Atom(v), f_1), (Zero(), f_2)) =>
    (Atom[A](v), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Plus(v, va), f_1), (Zero(), f_2)) =>
    (Plus[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Times(v, va), f_1), (Zero(), f_2)) =>
    (Times[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Star(v), f_1), (Zero(), f_2)) =>
    (Star[A](v), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((NTimes(v, va), f_1), (Zero(), f_2)) =>
    (NTimes[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Upto(v, va), f_1), (Zero(), f_2)) =>
    (Upto[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((From(v, va), f_1), (Zero(), f_2)) =>
    (From[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Rec(v, va), f_1), (Zero(), f_2)) =>
    (Rec[A](v, va), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((Charset(v), f_1), (Zero(), f_2)) =>
    (Charset[A](v), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
  case ((One(), f_1), (One(), f_2)) =>
    (equal_rexp[A](One[A](), One[A]()) match {
      case true => (One[A](), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
      case false => (Plus[A](One[A](), One[A]()),
                      ((a : vala[B]) => F_Plus[B](f_1, f_2, a)))
      })
  case ((One(), f_1), (Atom(v), f_2)) =>
    (equal_rexp[A](One[A](), Atom[A](v)) match {
      case true => (One[A](), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
      case false => (Plus[A](One[A](), Atom[A](v)),
                      ((a : vala[B]) => F_Plus[B](f_1, f_2, a)))
      })
  case ((One(), f_1), (Plus(v, va), f_2)) =>
    (equal_rexp[A](One[A](), Plus[A](v, va)) match {
      case true => (One[A](), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
      case false => (Plus[A](One[A](), Plus[A](v, va)),
                      ((a : vala[B]) => F_Plus[B](f_1, f_2, a)))
      })
  case ((One(), f_1), (Times(v, va), f_2)) =>
    (equal_rexp[A](One[A](), Times[A](v, va)) match {
      case true => (One[A](), ((a : vala[B]) => F_LEFT[vala[B], B](f_1, a)))
      case false => (Plus[A](One[A](), Times[A](v, va)),
                      ((a : vala[B]) => F_Plus[B](f_1, f_2, a)))
      })
