def simp[A : equal](x0 : rexp[A]) : (rexp[A], (vala[A]) => vala[A]) = x0 match {
  case Plus(r1, r2) => simp_Plus[A, A](simp[A](r1), simp[A](r2))
  case Times(r1, r2) => simp_Times[A, A](simp[A](r1), simp[A](r2))
  case Zero() => (Zero[A](), id[vala[A]])
  case One() => (One[A](), id[vala[A]])
  case Atom(v) => (Atom[A](v), id[vala[A]])
  case Star(v) => (Star[A](v), id[vala[A]])
  case NTimes(v, va) => (NTimes[A](v, va), id[vala[A]])
  case Upto(v, va) => (Upto[A](v, va), id[vala[A]])
  case From(v, va) => (From[A](v, va), id[vala[A]])
  case Rec(v, va) => (Rec[A](v, va), id[vala[A]])
  case Charset(v) => (Charset[A](v), id[vala[A]])
}

def minus_nat(m : nat, n : nat) : nat = (m, n) match {
  case (m, zero_nat()) => m
  case (zero_nat(), n) => zero_nat()
  case (Suc(m), Suc(n)) => minus_nat(m, n)
}

def one_nat : nat = Suc(zero_nat())

def deriv[A : equal](c : A, x1 : rexp[A]) : rexp[A] = (c, x1) match {
  case (c, Zero()) => Zero[A]()
  case (c, One()) => Zero[A]()
  case (ca, Atom(c)) =>
    (eq[A](ca, c) match { case true => One[A]() case false => Zero[A]() })
  case (c, Plus(r1, r2)) => Plus[A](deriv[A](c, r1), deriv[A](c, r2))
  case (c, Times(r1, r2)) =>
    (nullable[A](r1) match {
      case true => Plus[A](Times[A](deriv[A](c, r1), r2), deriv[A](c, r2))
      case false => Times[A](deriv[A](c, r1), r2) })
  case (c, Star(r)) => Times[A](deriv[A](c, r), Star[A](r))
  case (c, NTimes(r, n)) =>
    (equal_nat(n, zero_nat()) match { case true => Zero[A]()
      case false => Times[A](deriv[A](c, r),
                              NTimes[A](r, minus_nat(n, one_nat)))
      })
  case (c, Upto(r, n)) =>
    (equal_nat(n, zero_nat()) match { case true => Zero[A]()
      case false => Times[A](deriv[A](c, r), Upto[A](r, minus_nat(n, one_nat)))
      })
  case (c, From(r, n)) =>
    (equal_nat(n, zero_nat()) match {
      case true => Times[A](deriv[A](c, r), Star[A](r))
      case false => Times[A](deriv[A](c, r), From[A](r, minus_nat(n, one_nat)))
      })
  case (c, Rec(l, r)) => deriv[A](c, r)
  case (c, Charset(cs)) =>
    (member[A](c, cs) match { case true => One[A]() case false => Zero[A]() })
}

def slexer[A : equal](r : rexp[A], x1 : List[A]) : Option[vala[A]] = (r, x1)
  match {
  case (r, Nil) =>
    (nullable[A](r) match { case true => Some[vala[A]](mkeps[A](r))
      case false => None })
  case (r, c :: s) =>
    {
      val (rs, fr) =
        simp[A](deriv[A](c, r)) : ((rexp[A], (vala[A]) => vala[A]));
      (slexer[A](rs, s) match {
         case None => None
         case Some(v) => Some[vala[A]](injval[A](r, c, fr(v)))
       })
    }
}

} /* object SLULexer */
